// کۆنتێکستی ئۆسێنتیکەیشن
import React, { createContext, useState, useContext, useEffect } from 'react';
import { login as loginAPI, getCurrentUser } from '../services/api';
import { getFromLocalStorage, saveToLocalStorage, removeFromLocalStorage } from '../utils/helpers';

const AuthContext = createContext();

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth دەبێت لە ناو AuthProvider دا بەکاربهێنرێت');
  }
  return context;
};

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);
  const [isAuthenticated, setIsAuthenticated] = useState(false);

  // پشکنینی ئەگەر بەکارهێنەر پێشتر چووبێتە ژوورەوە
  useEffect(() => {
    const checkAuth = async () => {
      const token = getFromLocalStorage('token');
      const savedUser = getFromLocalStorage('user');

      if (token && savedUser) {
        try {
          // پشکنینی ڕاستی تۆکن لە سێرڤەر
          const response = await getCurrentUser();
          setUser(response.data.data);
          setIsAuthenticated(true);
        } catch (error) {
          // ئەگەر تۆکن نادروست بوو، سڕینەوەی
          removeFromLocalStorage('token');
          removeFromLocalStorage('user');
          setUser(null);
          setIsAuthenticated(false);
        }
      }
      setLoading(false);
    };

    checkAuth();
  }, []);

  // فەنکشنی چوونەژوورەوە
  const login = async (credentials) => {
    try {
      const response = await loginAPI(credentials);
      const { token, user } = response.data.data;

      // خەزنکردنی تۆکن و زانیاری بەکارهێنەر
      saveToLocalStorage('token', token);
      saveToLocalStorage('user', user);

      setUser(user);
      setIsAuthenticated(true);

      return { success: true };
    } catch (error) {
      return {
        success: false,
        message: error.response?.data?.message || 'هەڵەیەک ڕوویدا'
      };
    }
  };

  // فەنکشنی دەرچوون
  const logout = () => {
    removeFromLocalStorage('token');
    removeFromLocalStorage('user');
    setUser(null);
    setIsAuthenticated(false);
  };

  // نوێکردنەوەی زانیاری بەکارهێنەر
  const updateUser = (updatedUser) => {
    setUser(updatedUser);
    saveToLocalStorage('user', updatedUser);
  };

  const value = {
    user,
    isAuthenticated,
    loading,
    login,
    logout,
    updateUser
  };

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
};
